programCs.code:
using Tempo.Blazor.Configuration;

var builder = WebAssemblyHostBuilder.CreateDefault(args);

// Required: register Tempo.Blazor services (localization, ITmLocalizer)
builder.Services.AddTempoBlazor();

// Optional: register FluentValidation validators from your assemblies
builder.Services.AddTempoFluentValidation(typeof(MyValidator).Assembly);

// Optional: register ThemeService for dark mode support
builder.Services.AddScoped<ThemeService>();

// Optional: set culture for localization (supports 'en' and 'cs')
var culture = new System.Globalization.CultureInfo("cs");
System.Globalization.CultureInfo.DefaultThreadCurrentCulture = culture;
System.Globalization.CultureInfo.DefaultThreadCurrentUICulture = culture;

await builder.Build().RunAsync();

