:root {
  /* Change primary color to indigo */
  --tm-color-primary-500: #6366f1;
  --tm-color-primary-600: #4f46e5;
  --tm-color-primary-700: #4338ca;
  --tm-color-primary: var(--tm-color-primary-500);
  --tm-color-primary-hover: var(--tm-color-primary-600);
  --tm-color-primary-active: var(--tm-color-primary-700);

  /* Change default border radius */
  --tm-radius-md: 0.5rem;

  /* Change default font */
  --tm-font-sans: 'Inter', system-ui, sans-serif;
}
